Cheapest insertion with distance‑based regret and capacity feasibility check, evaluating both existing routes and empty slots, committing the minimal marginal cost increase while preserving all orders via forced new‐assign fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx
		bestAssignIdx := -1
		bestCostDelta := 1e100
		var savedCosts [MAXASSIGNS]float64
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}
		emptySlot := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				emptySlot = i
				break
			}
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			a := &dispatch.Assigns[i]
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestCostDelta {
						bestCostDelta = delta
						bestAssignIdx = i
					}
				}
			}
			a.RemoveShip(shipID)
			a.GenRoute()
			a.Cost = savedCosts[i]
		}
		if bestAssignIdx == -1 && emptySlot != -1 {
			slot := emptySlot
			if slot >= dispatch.AssignsLen {
				dispatch.AssignsLen = slot + 1
			}
			a := &dispatch.Assigns[slot]
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					bestCostDelta = newCost - oldCost
					bestAssignIdx = slot
				}
			}
			if bestAssignIdx != slot {
				a.RemoveShip(shipID)
				a.GenRoute()
				if slot >= dispatch.AssignsLen {
					dispatch.AssignsLen = slot
				}
			}
		}
		if bestAssignIdx == -1 {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				a := &dispatch.Assigns[newIdx]
				a.AddShip(shipID, ori, des)
				a.GenRoute()
				dispatch.AssignsLen++
				bestAssignIdx = newIdx
			}
		}
		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			a := &dispatch.Assigns[bestAssignIdx]
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAssignIdx + 1
			}
			a.AddShip(shipID, ori, des)
			a.GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

